sql:
SELECT unit_type, COUNT(unit_id) AS count_unit_type 
FROM energy_units 
GROUP BY unit_type;

SELECT COUNT(*) 
FROM users 
WHERE user_id NOT IN (
    SELECT DISTINCT user_id 
    FROM conversion_requests
);

SELECT COUNT(entry_id)
FROM conversion_table_entries
WHERE input_value > 1;

